const b = items[0].json.body || items[0].json;
const anchorInput = String(b.anchor || b['Anchor (keyword)'] || b.keyword || '').trim();
const geo = String(b.geo || b.GEO || '').trim();
let language = String(b.language || b.Language || '').trim();
const trRaw = String(b.translation || b['Anchor translation'] || '').trim().toLowerCase();
const translationMode = (trRaw === 'auto' || trRaw === 'автоматично') ? 'auto' : 'none';
const MAP = {
  'United States':{gl:'us',lang:'English'}, 'United Kingdom':{gl:'gb',lang:'English'},
  'Canada':{gl:'ca',lang:'English'}, 'Australia':{gl:'au',lang:'English'},
  'Poland':{gl:'pl',lang:'Polish'}, 'Germany':{gl:'de',lang:'German'},
  'France':{gl:'fr',lang:'French'}, 'Italy':{gl:'it',lang:'Italian'},
  'Spain':{gl:'es',lang:'Spanish'}, 'Mexico':{gl:'mx',lang:'Spanish'},
  'Brazil':{gl:'br',lang:'Portuguese'},
};
const m = MAP[geo] || {gl:'us', lang:'English'};
const fromName = (geo.match(/\(([A-Za-z]+)\)\s*$/)?.[1] || '').toLowerCase();
const gl = String(b.gl || '').trim().toLowerCase() || fromName || m.gl;
if (!language) language = m.lang;
if (!anchorInput) throw new Error('anchor is empty (body.anchor).');
if (!geo) throw new Error('geo is empty (body.geo).');
return [{ json: { anchorInput, geo, gl, language, translationMode } }];

parameters.text:
=Keyword: "{{ $json.keyword }}"
GEO: {{ $json.geo }}
Target language: {{ $json.language }}

Identify 3-5 distinct audience segments grounded in the RESEARCH below. Output JSON with this exact schema:
{ "audiences": [ { "segment_id":"A1","segment_name":string,"description":string,"demographics":string,"psychographics":string,"pain_points":[string],"desires":[string],"objections":[string],"vocab_to_use":[string],"notes":string } ] }
Rules:
- 3 segments if research is thin or audiences clearly overlap; 5 only when the research shows genuinely distinct sub-populations.
- segment_id is "A1".."A5" in order.
- Write all segment text fields IN {{ $json.language }}.
- Output MUST be valid JSON, nothing else.

RESEARCH (real Google SERP data for this keyword/GEO):
{{ $json.research }}

parameters.jsCode:
const b = $json.body || $json;
let picked = b.picked;
if (Array.isArray(picked)) picked = picked.join(',');
picked = String(picked || '').split(',').map(s => s.trim().toUpperCase()).filter(Boolean);
const all = b.audiences || [];
const sel = all.filter(a => picked.includes(String(a.segment_id).toUpperCase()));
if (sel.length < 1) throw new Error('No audiences picked (send body.picked, e.g. "A1,A3").');
if (sel.length > 5) throw new Error('Pick at most 5 audiences.');
return [{ json: {
  keyword: b.keyword, geo: b.geo, language: b.language,
  research: b.research || '', audiences: sel
} }];

parameters.text:
=Keyword: "{{ $json.keyword }}"
GEO: {{ $json.geo }}

=== RESEARCH (real Google SERP data — use this vocabulary verbatim where possible) ===
{{ $json.research }}

=== AUDIENCES SELECTED BY OPERATOR (HITL1) ===
{{ JSON.stringify($json.audiences) }}

=== OUTPUT SCHEMA ===
{ "headlines":[ { "headline_id":"H01","audience_id":"A1","angle_formula":"AF7","headline_kernel":"HK1","headline":"...","char_count":67,"reading_scope":"buyer"|"broadened","translation_ua":"..." } ] }
Generate 6-10 headlines per audience. Output MUST be valid JSON, nothing else.

parameters.jsCode:
const meta = $('Filter Picked Audiences').first().json;
const hs = (($json.output || {}).headlines) || [];
const FORBIDDEN = ["100% compensation","guaranteed million","maximum payout","$10m lawsuit","free money","government will pay","hidden cash","they don't want you to know","shocking truth","secret they're hiding","one weird trick"];
const kw = String(meta.keyword || '').toLowerCase();
const kwTokens = kw.split(/\s+/).filter(t => t.length > 3);
const dlen = s => { let n = 0; for (const ch of String(s||'')) { const c = ch.codePointAt(0); n += ((c>=0x3000&&c<=0x9FFF)||(c>=0xAC00&&c<=0xD7AF)||(c>=0xFF00&&c<=0xFFEF)||(c>=0x20000&&c<=0x2FFFF)) ? 2 : 1; } return n; };
hs.forEach(h => {
  const t = String(h.headline || ''); const v = []; const L = dlen(t);
  if (L < 50 || L > 90) v.push('len' + L);
  if (t.includes('!!')) v.push('!!');
  if (t.includes('?!')) v.push('?!');
  if ((t.match(/:/g) || []).length > 1) v.push('colon');
  const low = t.toLowerCase();
  for (const p of FORBIDDEN) { if (low.includes(p)) { v.push('forbidden'); break; } }
  if (kwTokens.length) { const m = kwTokens.filter(x => low.includes(x)).length; if (m / kwTokens.length < 0.5) v.push('kw'); }
  h.has_violations = v.length > 0; h._violations = v;
});
const aud = meta.audiences || [];
const audiences_slim = aud.map(a => ({ id: a.segment_id, name: a.segment_name, pain_points: a.pain_points || [], desires: a.desires || [], vocab_to_use: a.vocab_to_use || [] }));
const candidates_slim = hs.map(h => ({ headline_id: h.headline_id, audience_id: h.audience_id, AF: h.angle_formula, HK: h.headline_kernel, scope: h.reading_scope, headline: h.headline, has_violations: !!h.has_violations }));
return [{ json: { keyword: meta.keyword, geo: meta.geo, language: meta.language, audiences: aud, headlines: hs, audiences_slim, candidates_slim } }];

const sels = (($json.output || {}).selections) || [];
const vh = $('Validate Headlines').first().json;
const byId = {}; (vh.headlines || []).forEach(h => { byId[h.headline_id] = h; });
const audInput = vh.audiences || [];
const order = audInput.map(a => a.segment_id);
const nameById = {}; audInput.forEach(a => { nameById[a.segment_id] = a.segment_name; });
let rows = [];
sels.forEach(s => { (s.top_picks || []).forEach(p => {
  const h = byId[p.headline_id]; if (!h) return;
  rows.push({
    pick: false, rank: p.rank,
    audience: s.audience_id + ' · ' + (nameById[s.audience_id] || s.audience_name || ''),
    angle_formula: h.angle_formula, headline_kernel: h.headline_kernel,
    headline: h.headline, translation_ua: h.translation_ua || '', headline_id: p.headline_id
  });
}); });
rows.sort((a, b) => {
  const ai = order.indexOf(String(a.audience).split(' · ')[0]);
  const bi = order.indexOf(String(b.audience).split(' · ')[0]);
  if (ai !== bi) return ai - bi;
  return (a.rank || 99) - (b.rank || 99);
});
return [{ json: { top_picks: rows } }];

parameters.text:
=You are a search-keyword localization expert for paid media campaigns.
Translate the anchor keyword into the most idiomatic NATIVE search query a real user in {{ $('Normalize Request').first().json.geo }} would type into Google for the SAME intent.
Rules: use the actual term searchers use (not a literal dictionary translation); preserve commercial intent; use the target market's script; match native casing. If the input is already in {{ $('Normalize Request').first().json.language }}, return it unchanged.
Return ONLY the translated keyword as plain text — no quotes, no commentary.

Anchor: {{ $('Normalize Request').first().json.anchorInput }}
Target language: {{ $('Normalize Request').first().json.language }}

parameters.jsCode:
const serp = $json || {};
const meta = $('Normalize Request').first().json;
const keyword = (serp.search_parameters && serp.search_parameters.q) || meta.anchorInput;
const org = (serp.organic_results || []).slice(0, 10).map((r, i) =>
  `${i + 1}. ${r.title || ''} — ${r.snippet || ''} (${r.link || r.displayed_link || ''})`);
const related = (serp.related_searches || []).map(r => r.query || r.title || r).filter(Boolean);
const paa = (serp.related_questions || serp.people_also_ask || []).map(q => q.question || q.title || q).filter(Boolean);
let ai = '';
if (serp.answer_box) ai = serp.answer_box.answer || serp.answer_box.snippet || '';
else if (serp.ai_overview) ai = JSON.stringify(serp.ai_overview).slice(0, 1500);
let research = `SEARCH QUERY: ${keyword}
GEO: ${meta.geo}

TOP ORGANIC RESULTS:
${org.join('
')}`;
if (ai) research += `

AI OVERVIEW / ANSWER BOX:
${ai}`;
if (related.length) research += `

RELATED SEARCHES:
- ${related.join('
- ')}`;
if (paa.length) research += `

PEOPLE ALSO ASK:
- ${paa.join('
- ')}`;
return [{ json: { keyword, geo: meta.geo, gl: meta.gl, language: meta.language, research } }];

const meta = $('Clean SERP').first().json;
const audiences = (($json.output) || {}).audiences || [];
// Returned to the caller. Send this whole object back to /rsoc-generate-headlines
// together with `picked` (the segment_ids to keep).
return [{ json: {
  keyword: meta.keyword, geo: meta.geo, language: meta.language,
  research: meta.research, audiences
} }];
